BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?target ?targetName ?targetType ?relType WHERE {
  ?elem vocab:NamedElement_name "APS%20Interface%20Requirements" .
  { ?elem vocab:Dependency_client ?target }
  UNION
  { ?elem vocab:Dependency_supplier ?target }
  UNION
  { ?elem vocab:Generalization_specific ?target }
  UNION
  { ?target vocab:Generalization_general ?elem }
  UNION
  { ?elem vocab:satisfy ?target }
  UNION
  { ?elem vocab:verify ?target }
  UNION
  { ?elem vocab:allocate ?target }
  UNION
  { ?elem vocab:refine ?target }
  OPTIONAL { ?target vocab:NamedElement_name ?targetName }
  OPTIONAL { ?target rdf:type ?targetType }
  BIND(STR(?relType) AS ?relType)
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?type WHERE {
  ?elem vocab:NamedElement_name "APS%20Interface%20Requirements" .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
}
LIMIT 10

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?owner ?ownerName ?ownerType WHERE {
  { 
    ?elem vocab:NamedElement_name "APS%20Interface%20Requirements" .
    ?elem vocab:Element_owner ?owner .
  }
  UNION
  {
    ?elem vocab:NamedElement_name "APS%20Interface%20Requirements" .
    ?owner vocab:Element_ownedElement+ ?elem .
  }
  ?owner vocab:NamedElement_name ?ownerName .
  ?owner rdf:type ?ownerType .
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?qn WHERE {
  ?elem vocab:NamedElement_name "APS%20Interface%20Requirements" .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
  OPTIONAL { ?elem vocab:NamedElement_qualifiedName ?qn }
}
LIMIT 10

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?req ?reqName ?qn WHERE {
  ?req rdf:type vocab:tmt%20requirement .
  ?req vocab:NamedElement_name ?reqName .
  OPTIONAL { ?req vocab:NamedElement_qualifiedName ?qn }
  FILTER(CONTAINS(LCASE(?qn), "aps") && CONTAINS(LCASE(?qn), "interface"))
}
LIMIT 25
